const item = $input.first().json || {};
const staticData = $getWorkflowStaticData('global');
const expectedIds = String($env.CRITICAL_WORKFLOW_IDS || '')
  .split(',')
  .map(s => s.trim())
  .filter(Boolean);

const baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';

if (expectedIds.length === 0) {
  delete staticData.activationCheckUncertain;
  return [{ json: { activationConfigured: false, activationIssue: false, hasDeactivated: false, activationUncertain: false, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: 0, activationMessage: 'CRITICAL_WORKFLOW_IDS not configured' } }];
}

if (item.error && item.error.message) {
  staticData.activationCheckUncertain = {
    timestamp: new Date().toISOString(),
    reason: item.error.message
  };
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: false, activationUncertain: true, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: expectedIds.length, activationMessage: item.error.message } }];
}

const data = item.data || item;
const arr = Array.isArray(data) ? data : (Array.isArray(data.data) ? data.data : []);

if (!Array.isArray(arr)) {
  staticData.activationCheckUncertain = {
    timestamp: new Date().toISOString(),
    reason: 'Unexpected active workflows API response shape'
  };
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: false, activationUncertain: true, deactivatedIds: [], deactivatedUrls: [], activeCount: 0, expectedCount: expectedIds.length, activationMessage: 'Unexpected active workflows API response shape' } }];
}

const activeIds = new Set(arr.map(w => String(w.id)));
const deactivatedIds = expectedIds.filter(id => !activeIds.has(String(id)));
const deactivatedUrls = deactivatedIds.map(id => baseUrl + '/workflow/' + id);

if (deactivatedIds.length > 0) {
  delete staticData.activationCheckUncertain;
  return [{ json: { activationConfigured: true, activationIssue: true, hasDeactivated: true, activationUncertain: false, deactivatedIds: deactivatedIds, deactivatedUrls: deactivatedUrls, activeCount: activeIds.size, expectedCount: expectedIds.length, activationMessage: deactivatedIds.length + ' critical workflow(s) inactive' } }];
}

delete staticData.activationCheckUncertain;
return [{ json: { activationConfigured: true, activationIssue: false, hasDeactivated: false, activationUncertain: false, deactivatedIds: [], deactivatedUrls: [], activeCount: activeIds.size, expectedCount: expectedIds.length, activationMessage: 'All critical workflows active' } }];

