const crypto = require('crypto');

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const statusItem = (() => {
  try { return $('System Status').first().json || {}; } catch(e) { return {}; }
})();
const activationItem = (() => {
  try { return $('Detect Activation State').first().json || {}; } catch(e) { return {}; }
})();
const dmsItem = (() => {
  try { return $('Check DMS Result').first().json || {}; } catch(e) { return {}; }
})();
const staticData = $getWorkflowStaticData('global');

const isDbError = !!(statusItem.error && typeof statusItem.error === 'object' && statusItem.error.message);
const cs = isDbError ? 'unknown' : (statusItem.circuit_status || 'unknown');
const ec = isDbError ? 0 : (parseInt(statusItem.error_count, 10) || 0);
const errHour = isDbError ? 0 : (parseInt(statusItem.errors_last_hour, 10) || 0);
const err24h = isDbError ? 0 : (parseInt(statusItem.errors_last_24h, 10) || 0);
const lastHeartbeatAt = statusItem.last_heartbeat_at || null;

let topSources = [];
try {
  const raw = statusItem.top_error_sources;
  if (typeof raw === 'string') topSources = JSON.parse(raw);
  else if (Array.isArray(raw)) topSources = raw;
} catch(e) { topSources = []; }

const circuitIcon = cs === 'closed' ? '\u{1F7E2}' : cs === 'half_open' ? '\u{1F7E1}' : cs === 'open' ? '\u{1F534}' : '\u26AA';
const trend = errHour >= 3 ? '\u{1F534} spike' : err24h >= 10 ? '\u{1F7E1} elevated' : '\u{1F7E2} stable';

const dmsFiredThisCycle = dmsItem.dmsFiredThisCycle || false;
const cachedCount = (staticData.eventFailures && staticData.eventFailures.length) || 0;
const droppedCount = staticData.droppedCacheCount || 0;

let emergencyNote = '';
if (cachedCount > 0) {
  emergencyNote = '\n\u{1F6A8} <b>Emergency Cache:</b> ' + cachedCount + ' failed event(s)';
  if (droppedCount > 0) emergencyNote += ' (' + droppedCount + ' dropped due to overflow)';
}

let dmsNote = '';
if (staticData.lastDeadMansSwitchFailure && !dmsFiredThisCycle) {
  dmsNote = '\n\u26A0\uFE0F <b>DMS Failure:</b> <code>' + htmlEscape(String(staticData.lastDeadMansSwitchFailure).substring(0, 200)) + '</code>';
}

let orphanNote = '';
if (staticData.orphanUncertainty) {
  orphanNote = '\n\u26A0\uFE0F <b>Orphan Uncertain:</b> ' + htmlEscape(staticData.orphanUncertainty.reason);
}

let activationNote = '';
if (staticData.activationCheckUncertain) {
  activationNote = '\n\u26A0\uFE0F <b>Activation Uncertain:</b> ' + htmlEscape(staticData.activationCheckUncertain.reason);
} else if (activationItem.hasDeactivated) {
  activationNote = '\n\u26A0\uFE0F <b>Inactive Critical:</b> ' + activationItem.deactivatedUrls.map(u => '<a href="' + u + '">' + u + '</a>').join(', ');
} else if (activationItem.activationConfigured) {
  activationNote = '\n\u2705 <b>Workflows:</b> ' + activationItem.expectedCount + '/' + activationItem.expectedCount + ' active';
}

const dbNote = isDbError ? '\n\u{1F534} <b>DATABASE UNREACHABLE</b>' : '';

const isDegraded = isDbError || cs === 'open' || cs === 'half_open' || cachedCount > 0 || !!staticData.lastDeadMansSwitchFailure || !!staticData.orphanUncertainty || !!staticData.activationCheckUncertain || !!activationItem.hasDeactivated;
const isCritical = isDbError || cs === 'open';
const verdict = isCritical ? '\u{1F534} CRITICAL' : isDegraded ? '\u{1F7E1} DEGRADED' : '\u{1F7E2} HEALTHY';

let topSourcesLine = '';
if (topSources.length > 0) {
  topSourcesLine = '\n\n\u{1F3C6} <b>Top Sources (24h):</b>';
  topSources.forEach(function(src, i) {
    topSourcesLine += '\n' + (i + 1) + '. ' + htmlEscape(src.workflow_name) + ' \u2014 ' + src.error_count + ' errors' + (src.errors_1h > 0 ? ' (' + src.errors_1h + ' in 1h)' : '');
  });
}

const text = '\u{1F493} <b>SUPERVISOR \u2014 ' + verdict + '</b>\n\n'
  + circuitIcon + ' <b>Circuit:</b> ' + cs + ' (' + ec + '/5)\n'
  + (dmsItem.dmsOk ? '\u{1F7E2}' : '\u{1F534}') + ' <b>DMS:</b> ' + (dmsItem.dmsOk ? 'ok' : 'FAILED') + '\n'
  + (activationItem.activationConfigured ? (activationItem.activationIssue ? '\u{1F534}' : '\u{1F7E2}') + ' <b>Workflows:</b> ' + (activationItem.activationIssue ? activationItem.activationMessage : activationItem.expectedCount + '/' + activationItem.expectedCount + ' active') : '\u26AA <b>Workflows:</b> not configured') + '\n'
  + (staticData.orphanUncertainty ? '\u{1F7E1}' : '\u26AA') + ' <b>Orphans:</b> ' + (staticData.orphanUncertainty ? 'uncertain' : 'none detected') + '\n'
  + '\u{1F4CA} <b>Trend:</b> ' + trend + '\n'
  + '\n<b>Errors:</b> ' + errHour + ' (1h) \u00B7 ' + err24h + ' (24h)'
  + topSourcesLine
  + dbNote + emergencyNote + dmsNote + orphanNote + activationNote
  + '\n\n<b>Timestamp:</b> ' + new Date().toISOString();

const hashInput = cs + ':' + ec + ':' + errHour + ':' + err24h + ':' + isDbError + ':' + cachedCount + ':' + droppedCount + ':' + !!staticData.lastDeadMansSwitchFailure + ':' + !!staticData.orphanUncertainty + ':' + !!staticData.activationCheckUncertain + ':' + !!activationItem.hasDeactivated + ':' + (activationItem.deactivatedIds?.join(',') || '') + ':' + topSources.map(s => s.workflow_name + ':' + s.error_count).join(',');
const messageHash = crypto.createHash('md5').update(hashInput).digest('hex');
const lastSentHash = staticData.lastHeartbeatHash || '';
const isDuplicate = messageHash === lastSentHash;

const now = new Date();
const currentHourKey = now.toISOString().slice(0, 13);
const lastHealthyHourSent = staticData.lastHealthyHourSent || '';

let shouldSend = false;
let sendReason = 'suppressed';

if (isDbError) {
  shouldSend = true;
  sendReason = 'database_unreachable';
} else if (isDegraded && !isDuplicate) {
  shouldSend = true;
  sendReason = 'degraded_state_changed';
} else if (!isDegraded && now.getMinutes() < 5 && lastHealthyHourSent !== currentHourKey) {
  shouldSend = true;
  sendReason = 'hourly_healthy_pulse';
}

return [{
  json: {
    text: text,
    messageHash: messageHash,
    isDuplicate: isDuplicate,
    isDegraded: isDegraded,
    isCritical: isCritical,
    verdict: verdict,
    shouldSend: shouldSend,
    sendReason: sendReason,
    dbError: isDbError,
    circuit_status: cs,
    error_count: ec,
    errors_last_hour: errHour,
    errors_last_24h: err24h,
    emergency_cache_count: cachedCount,
    dropped_cache_count: droppedCount,
    dms_failure_active: !!staticData.lastDeadMansSwitchFailure,
    orphan_uncertain: !!staticData.orphanUncertainty,
    activation_uncertain: !!staticData.activationCheckUncertain,
    activation_issue: !!activationItem.activationIssue,
    activation_deactivated_ids: activationItem.deactivatedIds || [],
    currentHourKey: currentHourKey
  }
}];

const staticData = $getWorkflowStaticData('global');
const evalData = (() => {
  try { return $('Evaluate System Health').first().json; } catch(e) { return {}; }
})();

staticData.lastHeartbeatHash = evalData.messageHash || '';

if (!evalData.isDegraded && evalData.currentHourKey) {
  staticData.lastHealthyHourSent = evalData.currentHourKey;
}

staticData.eventFailures = [];
staticData.droppedCacheCount = 0;
staticData.lastSuccessfulHeartbeatAt = new Date().toISOString();

return [{ json: { cacheCleared: true, hashUpdated: true, lastSuccessfulHeartbeatAt: staticData.lastSuccessfulHeartbeatAt } }];

const staticData = $getWorkflowStaticData('global');
const item = $input.first().json || {};
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  traceId: item.traceId || 'unknown',
  eventType: 'alert_failed',
  source: 'Heartbeat Monitor',
  workflowName: 'Heartbeat Monitor',
  failedNode: item.failedNode || 'unknown',
  reason: item.error?.message || 'Telegram, Postgres, or HTTP delivery failed'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true, count: staticData.eventFailures.length, droppedCacheCount: staticData.droppedCacheCount || 0 } }];
